using Microsoft.ML.Data;

namespace TicketClassifier.Models;

/// <summary>
/// Input schema that maps to the training CSV columns.
/// </summary>
public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

/// <summary>
/// ML.NET prediction output.
/// </summary>
public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public record PredictRequest(string Subject, string Description, int Priority);

public record PredictResponse(string Category, Dictionary<string, float> Confidence);

public record EvaluationMetrics(
    double MacroAccuracy,
    double MicroAccuracy,
    double LogLoss,
    double LogLossReduction,
    string ConfusionMatrix);

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains, evaluates, and serves predictions for support-ticket classification.
/// Registered as a singleton so training runs once at startup.
/// </summary>
public sealed class TicketModelService
{
    private readonly MLContext _ml;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _engine;
    private readonly VBuffer<ReadOnlyMemory<char>> _labelSlots;

    public EvaluationMetrics Metrics { get; }

    public TicketModelService(string dataPath)
    {
        _ml = new MLContext(seed: 42);

        // Load the CSV
        IDataView allData = _ml.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Build pipeline:
        //   1. Combine Subject + Description into a single text feature
        //   2. Featurize text with n-grams
        //   3. Include Priority as a numeric feature
        //   4. Concatenate everything into "Features"
        //   5. Map Category string -> key for the trainer, then back for output
        var pipeline = _ml.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject))
            .Append(_ml.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_ml.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_ml.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(_ml.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_ml.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Train / test split — with very few rows we use 20 % for testing
        var split = _ml.Data.TrainTestSplit(allData, testFraction: 0.2);

        _model = pipeline.Fit(split.TrainSet);

        // Evaluate
        IDataView predictions = _model.Transform(split.TestSet);
        var eval = _ml.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        Metrics = new EvaluationMetrics(
            MacroAccuracy: Math.Round(eval.MacroAccuracy, 4),
            MicroAccuracy: Math.Round(eval.MicroAccuracy, 4),
            LogLoss: Math.Round(eval.LogLoss, 4),
            LogLossReduction: Math.Round(eval.LogLossReduction, 4),
            ConfusionMatrix: eval.ConfusionMatrix.GetFormattedConfusionTable());

        // Prediction engine (thread-safe wrapper created once)
        _engine = _ml.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Grab the ordered label names so we can map Score[] back to category strings
        var labelCol = _model.GetOutputSchema(allData.Schema)["PredictedLabel"];
        labelCol.GetKeyValues(ref _labelSlots);
    }

    public PredictResponse Predict(PredictRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        TicketPrediction result = _engine.Predict(input);

        // Build a category -> confidence map from the Score array
        var labels = _labelSlots.DenseValues().ToArray();
        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < labels.Length; i++)
        {
            confidence[labels[i].ToString()] = MathF.Round(result.Score[i], 4);
        }

        return new PredictResponse(result.Category, confidence);
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController(TicketModelService modelService) : ControllerBase
{
    /// <summary>POST /api/ticket/predict — classify a support ticket.</summary>
    [HttpPost("predict")]
    public ActionResult<PredictResponse> Predict([FromBody] PredictRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        return Ok(modelService.Predict(request));
    }

    /// <summary>GET /api/ticket/metrics — return evaluation metrics from the last training run.</summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        return Ok(modelService.Metrics);
    }
}

