namespace TicketClassifier.Models;

public record PredictRequest(string Subject, string Description, int Priority);

public record PredictResponse(string Category, Dictionary<string, float> Confidence);

public record EvaluationMetrics(
    double MacroAccuracy,
    double MicroAccuracy,
    double LogLoss,
    double LogLossReduction,
    string ConfusionMatrix);

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController(TicketModelService modelService) : ControllerBase
{
    /// <summary>POST /api/ticket/predict — classify a support ticket.</summary>
    [HttpPost("predict")]
    public ActionResult<PredictResponse> Predict([FromBody] PredictRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        return Ok(modelService.Predict(request));
    }

    /// <summary>GET /api/ticket/metrics — return evaluation metrics from the last training run.</summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        return Ok(modelService.Metrics);
    }
}

